module temp_shutdown_controller (
    input clk,
    input rst,
    input [7:0] temperature,
    output reg shutdown
);
    parameter THRESHOLD = 8'd80;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst) begin
            shutdown <= 1'b0;
        end else if (temperature > THRESHOLD) begin
            shutdown <= 1'b1;
        end else begin
            shutdown <= 1'b0;
        end
    end
endmodule
